import{_ as l,o as i,c as e,a0 as t}from"./chunks/framework.r0TJpsHX.js";const p=JSON.parse('{"title":"Планы на 2026 год","description":"","frontmatter":{"title":"Планы на 2026 год","date":"2025-12-12T00:00:00.000Z"},"headers":[],"relativePath":"posts/2025-12-12-rational-planning.md","filePath":"posts/2025-12-12-rational-planning.md"}'),r={name:"posts/2025-12-12-rational-planning.md"};function o(n,a,h,s,u,d){return i(),e("div",null,[...a[0]||(a[0]=[t('<p>Это вторая статья из цикла &quot;Системное планирование&quot;. <a href="https://alterfo.github.io/posts/2022/10/16/timemanagement/" target="_blank" rel="noreferrer">Первая — о метафизике тайм-менеджмента</a></p><p>Этот пост — мой <a href="https://en.wikipedia.org/wiki/Commitment_device" target="_blank" rel="noreferrer">commitment device</a>, если вы понимаете, о чём я.</p><h2 id="диагностика" tabindex="-1">Диагностика <a class="header-anchor" href="#диагностика" aria-label="Permalink to &quot;Диагностика&quot;">​</a></h2><h3 id="реестр-проблем" tabindex="-1">Реестр проблем <a class="header-anchor" href="#реестр-проблем" aria-label="Permalink to &quot;Реестр проблем&quot;">​</a></h3><ul><li>Сбои в подаче энергии. Гипотезы первопричин: сбои в режиме, никотин, выходы из дома раз в месяц, токсичные отношения, шум из вентиляции (идеальная метафора), недо-кухня.</li><li>Карьерный потолок. Ощущение, что вклад недооценён (три отказа в повышении из-за &quot;коммуникаций&quot;). Творчество (музыка) не выходит на желаемый уровень. Нарциссическая часть голодает. Гипотеза: ошибка в стратегии - ожидание валидации извне вместо создания контролируемых источников.</li></ul><h2 id="wishlist" tabindex="-1">Wishlist <a class="header-anchor" href="#wishlist" aria-label="Permalink to &quot;Wishlist&quot;">​</a></h2><ul><li>Повысить QoL (субъективное качество жизни).</li><li>Автоматизировать получение признание (controlled recognition loop).</li><li>Увеличить КПСД (коэффициент полезного социального действия)</li></ul><h2 id="ландшафт" tabindex="-1">Ландшафт <a class="header-anchor" href="#ландшафт" aria-label="Permalink to &quot;Ландшафт&quot;">​</a></h2><ul><li>Энергетический ботлнек (3 из 10)</li><li>Удалённая работа, город Казань, возраст 40 лет, невротическая личность с нарциссическим ядром (не диагноз, а архитектурная особенность).</li><li>Склонность к гиперответственности и последующему выгоранию</li><li>Травматичный опыт коммуникаций (буллинг, манипуляции)</li></ul><h2 id="функциональные-требования" tabindex="-1">Функциональные требования <a class="header-anchor" href="#функциональные-требования" aria-label="Permalink to &quot;Функциональные требования&quot;">​</a></h2><h3 id="платформа-режим" tabindex="-1">Платформа (режим) <a class="header-anchor" href="#платформа-режим" aria-label="Permalink to &quot;Платформа (режим)&quot;">​</a></h3><ul><li>[Spike] Анализ причин перенапряжения</li><li>Режим &quot;ночной свет&quot; на всех устройствах после 21:00.</li><li>Медитация в 22:00.</li><li>Чай габа/фитоседан.</li><li>Отказ от сна после работы.</li><li>Плотный завтрак в 8:00</li><li>Отказ от второй кружки кофе. Замена чаем/водой/молоком.</li><li>Замена никотина приседаниями.</li><li>Прогулка-освещение, в календарь каждый день на 15 минут.</li><li>Утренние и вечерние водные процедуры.</li></ul><p>Критерии приёмки: спустя 4 недели субъективный уровень энергии поднялся минимум на 2 пункта. План Б: отпуск, путешествия, смена обстановки.</p><h3 id="коммуникации" tabindex="-1">Коммуникации <a class="header-anchor" href="#коммуникации" aria-label="Permalink to &quot;Коммуникации&quot;">​</a></h3><ul><li>[Spike] Разобрать тяжелые ситуации по схеме SBI (ситуация-поведение-реакция)</li><li>Выписать и провести полевые испытания на триггерах по технике ITP (если, тогда)</li><li>Провести серию поведенческих экспериментов с подробным отчетом (Small Talk, переговоры, знакомство)</li></ul><p>Критерии приёмки: комфорт в общении субъективно поднялся минимум на два пункта</p><h3 id="процессы-музыка" tabindex="-1">Процессы (музыка) <a class="header-anchor" href="#процессы-музыка" aria-label="Permalink to &quot;Процессы (музыка)&quot;">​</a></h3><ul><li>От стохановщины к аджайлу. В течение квартала сфокусироваться на одном параметре (работа с пространством).</li><li>Найти автора текстов. Предложить взаимопомощь и сотрудничество.</li></ul><p>Критерии приёмки: выпущен мини-альбом в цифровой дистрибьюции (bandcamp, например) из 3-5 законченных треков</p><h3 id="релизы-признание" tabindex="-1">Релизы (признание) <a class="header-anchor" href="#релизы-признание" aria-label="Permalink to &quot;Релизы (признание)&quot;">​</a></h3><ul><li>Подать заявку на осеннюю конференцию. Подготовить тезисы и доклад.</li><li>Развить блог в популярных источниках (тг, вк, интранет)</li></ul><p>Критерии приёмки: Проведён хотя бы 1 публичный доклад. Минимум 10 участников.</p><h2 id="заключение-лозунги-и-миссия" tabindex="-1">Заключение (лозунги и миссия) <a class="header-anchor" href="#заключение-лозунги-и-миссия" aria-label="Permalink to &quot;Заключение (лозунги и миссия)&quot;">​</a></h2><ul><li>Я изменяю параметры своей системы чтобы среда была вынуждена реагировать и меняться.</li><li>Я избавляюсь от страха экспериментировать.</li></ul><p>Вопрос к вам, читателям: Какие у вас системные ошибки, которые маскируются под лень или обстоятельства? Давайте отлаживать вместе.</p>',25)])])}const m=l(r,[["render",o]]);export{p as __pageData,m as default};
